#!/usr/bin/perl
use strict;
use warnings;
use CGI;

my $cgi = CGI->new;
print $cgi->header('text/plain');

my $log_dir = '/path/to/logs';
my $filename = $cgi->param('logfile');

if ($filename && $filename =~ /^[\w\-.]+$/ && -f "$log_dir/$filename") {
    open(my $fh, '<', "$log_dir/$filename") or die "Could not open file: $!";
    while (my $line = <$fh>) {
        print $line;
    }
    close $fh;
} else {
    print "Invalid or missing log filename.";
}